    // Start with base query and build conditions dynamically
    auto query = sqlgen::read<std::vector<Book>>;

    // Build WHERE conditions based on provided filters
    auto conditions = std::vector<decltype("title"_c == "")>{};

    if (filters.title_keyword) {
