  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Create SQLite database connection
  auto conn_result = sqlgen::sqlite::connect(":memory:");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create temporary table for OrderItem data
  auto create_table_stmt = R"(
    CREATE TEMPORARY TABLE OrderItem (
      item_id INTEGER PRIMARY KEY,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate REAL
    )
  )";

  auto execute_result = conn->execute(create_table_stmt);
  if (!execute_result) {
    throw std::runtime_error("Failed to create table");
  }

  // 3. Insert data into the table
  auto write_result = write(conn, items);
  if (!write_result) {
    throw std::runtime_error("Failed to insert data");
  }

  // 4. Build complex query using sqlgen's fluent API
  auto query = read<std::vector<OrderMetrics>>
    | select_from<OrderItem>(
        "item_id"_c,
        "order_id"_c,
        "product_id"_c,
        "unit_price"_c,
        "quantity"_c,
        "discount_rate"_c,
        "tax_rate"_c,

        // Arithmetic operations and business logic
        ("unit_price"_c * "quantity"_c) | as<"gross_total">,
        ("unit_price"_c * "quantity"_c * (1 - ("discount_rate"_c / 100.0))) | as<"discounted_total">,
        ("unit_price"_c * "quantity"_c * (1 - ("discount_rate"_c / 100.0)) * (1 + ("tax_rate"_c / 100.0))) | as<"final_total">,
        ("unit_price"_c * "quantity"_c / "quantity"_c) | as<"unit_cost">,
        ("quantity"_c % 10) | as<"quantity_group">,
        ("unit_price"_c * 0.3) | as<"estimated_profit">
      );

  // 5. Execute the query and map results
  auto result = query(conn);
  if (!result) {
    throw std::runtime_error("Query execution failed");
  }

  return result.value();
}

}  // namespace calculate_order_metrics

