        {1, 1000.0, "active"},
        {2, 2000.0, "inactive"},
        {3, 1500.0, "pending"}
    };

    auto write_result = sqlgen::write(conn, initial_data);
    if (!write_result) {
      return false;
    }

    // 4. Update balance and status using set() operations
    auto update_result = (sqlgen::update<Account>("balance"_c.set(1500.0), "status"_c.set("updated"))
        | sqlgen::where("account_id"_c == 1))(conn);

    if (!update_result) {
      return false;
    }

    // 5. Verify changes using sqlgen::read
    auto read_result = sqlgen::read<std::vector<Account>>(conn);
    if (!read_result) {
      return false;
